2996   if (match(RHS, m_One())) {
2997     switch (Pred) {
2998     case ICmpInst::ICMP_SGE:
2999       // icmp sge X, 1 --> icmp sgt X, 0
3000       Pred = ICmpInst::ICMP_SGT;
3001       return true;
3002     case ICmpInst::ICMP_UGE:
3003       // icmp uge X, 1 --> icmp ugt X, 0
3004       Pred = ICmpInst::ICMP_UGT;
