3006     case ICmpInst::ICMP_SLT:
3007       // icmp slt X, 1 --> icmp sle X, 0
3008       Pred = ICmpInst::ICMP_SLE;
3009       return true;
3010     case ICmpInst::ICMP_ULT:
3011       // icmp ult X, 1 --> icmp ule X, 0
3012       Pred = ICmpInst::ICMP_ULE;
3013       return true;
