3089 
3090   Value *X;
3091   const APInt *C;
3092   if (!match(RHS, m_APIntAllowPoison(C)))
3093     return nullptr;
3094 
3095   // Sign-bit checks can be optimized to true/false after unsigned
3096   // floating-point casts:
3097   // icmp slt (bitcast (uitofp X)),  0 --> false
3098   // icmp sgt (bitcast (uitofp X)), -1 --> true
3099   if (match(LHS, m_ElementWiseBitCast(m_UIToFP(m_Value(X))))) {
3100     bool TrueIfSigned;
3101     if (isSignBitCheck(Pred, *C, TrueIfSigned))
3102       return ConstantInt::getBool(ITy, !TrueIfSigned);
3103   }
3104 
3105   // Rule out tautological comparisons (eg., ult 0 or uge 0).
3106   ConstantRange RHS_CR = ConstantRange::makeExactICmpRegion(Pred, *C);
3107   if (RHS_CR.isEmptySet())
3108     return ConstantInt::getFalse(ITy);
3109   if (RHS_CR.isFullSet())
3110     return ConstantInt::getTrue(ITy);
3111 
3112   ConstantRange LHS_CR =
3113       computeConstantRange(LHS, CmpInst::isSigned(Pred), Q.IIQ.UseInstrInfo);
3114   if (!LHS_CR.isFullSet()) {
3115     if (RHS_CR.contains(LHS_CR))
3116       return ConstantInt::getTrue(ITy);
3117     if (RHS_CR.inverse().contains(LHS_CR))
3118       return ConstantInt::getFalse(ITy);
3119   }
